// Extract and structure the script data
const scriptText = $input.first().json.content.parts[0].text;
const ideaData = $('Get Approved Ideas').item.json;

// Calculate script metadata
const wordCount = scriptText.split(/\s+/).length;
const estimatedDuration = Math.round((wordCount / 2.5) * 1); // ~2.5 words per second

// Parse script into scenes (split by [pause])
const scenes = scriptText
  .split('[pause]')
  .map(scene => scene.trim())
  .filter(scene => scene.length > 0)
  .map((scene, index) => ({
    scene_number: index + 1,
    text: scene,
    duration_estimate: Math.round((scene.split(/\s+/).length / 2.5) * 1)
  }));
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
return {
  script_id: generateUUID(),
  idea_id: ideaData.idea_id,
  hook_variant_id: ideaData.hook_variant_id,
  transcript_id: ideaData.transcript_id,

  script_text: scriptText,
  word_count: wordCount,
  duration_sec: estimatedDuration,
  scenes: scenes,

  status: 'draft',

  // Pass through for Slack notification
  hook_text: ideaData.hook_text,
  idea_text: ideaData.idea_text,
  niche: ideaData.niche
};

